        let size = mem::size_of::<T>();
        if self.next_free + size > self.buffer.len() {
            return None;
        }
        let ptr = unsafe { self.buffer.as_mut_ptr().add(self.next_free) as *mut T };
        self.next_free += size;
        Some(ptr)
